import{_ as a,c as l,o as s,aj as e,bx as t,by as p,bz as r,bA as n,bB as h,bC as o,bD as d}from"./chunks/framework.CoirRWyn.js";const f=JSON.parse('{"title":"3.2 图像理解 [Image understanding]","description":"","frontmatter":{},"headers":[],"relativePath":"module_3/3.2图像理解[Image understanding].md","filePath":"module_3/3.2图像理解[Image understanding].md"}'),k={name:"module_3/3.2图像理解[Image understanding].md"};function g(c,i,m,b,u,_){return s(),l("div",null,[...i[0]||(i[0]=[e('<h1 id="_3-2-图像理解-image-understanding" tabindex="-1">3.2 图像理解 [Image understanding] <a class="header-anchor" href="#_3-2-图像理解-image-understanding" aria-label="Permalink to “3.2 图像理解 [Image understanding]”">​</a></h1><blockquote><p>主题：如何在 Prompt 中加入图片，让 AI 读取图像信息、理解图像内容，并结合文字指令完成解释、识别、计算、转写和总结等任务。</p></blockquote><p><img src="'+t+'" alt="alt text"></p><p>用户不仅可以向 AI 输入文字，还可以上传图片，把图片作为 Prompt 输入，让 AI 根据图片中的视觉信息进行分析、解释、提取文字或生成总结。</p><p>AI 已经具备一定的图像理解能力，能够读取图像中的基本文字，也能够对图像内容进行较合理的解释；</p><p>但它并不总能准确识别细粒度细节，尤其是图片模糊、信息被遮挡、物体外观相似或任务具有高风险时，仍然需要人工核查。</p><h2 id="图片可以作为-prompt-的一部分" tabindex="-1">图片可以作为 Prompt 的一部分 <a class="header-anchor" href="#图片可以作为-prompt-的一部分" aria-label="Permalink to “图片可以作为 Prompt 的一部分”">​</a></h2><p>传统 Prompt 主要依赖文字输入，而多模态模型允许用户把图片也放进 Prompt 中。</p><p>图片可以提供文字无法充分描述的上下文，例如：</p><ul><li>白板上的课程内容；</li><li>手写笔记；</li><li>餐厅账单；</li><li>会议白板和便利贴；</li><li>家庭旧信件或手写食谱；</li><li>商品、设备、场景或截图。</li></ul><p>使用图片的价值在于：用户不需要先把图像内容完整转写成文字，而是可以直接上传图片，让 AI 从图像中提取可用信息，再根据问题给出回答。</p><p><img src="'+p+'" alt="alt text"></p><p>如上图示例所示：让 AI 理解教学场景图片</p><p>视频中展示了一个课堂白板的例子。用户上传一张教授站在白板前的图片，并询问：“这节课在讲什么？”</p><p>AI 能够从图片中识别出一些关键信息，例如：</p><ul><li>图片中有人在讲课；</li><li>白板上包含卷积神经网络相关内容；</li><li>图中可能涉及输入体积、卷积计算等概念；</li><li>即使教授挡住了部分白板，AI 仍能根据可见内容做出较合理推断。</li></ul><p>这个例子说明，AI 可以结合图像中的文字、图形和场景关系进行综合理解，而不只是机械地读取图片上的文字。</p><h2 id="图片理解的局限-细节可能被忽略" tabindex="-1">图片理解的局限：细节可能被忽略 <a class="header-anchor" href="#图片理解的局限-细节可能被忽略" aria-label="Permalink to “图片理解的局限：细节可能被忽略”">​</a></h2><p>AI 对图片的理解并不总是可靠，尤其容易遗漏细粒度细节。</p><h3 id="案例1" tabindex="-1">案例1： <a class="header-anchor" href="#案例1" aria-label="Permalink to “案例1：”">​</a></h3><p>例如，在健身器械图片中，用户询问“这些是什么器械”。由于两台器械外观看起来相似，如果图片较模糊，AI 可能把左边器械识别为胸推器械，把右边识别为卷腹器械，但这个判断可能是错误的。</p><p><img src="'+r+'" alt="alt text"></p><p>这说明：</p><ul><li>AI 更擅长识别整体轮廓和明显特征；</li><li>对外观相近的物体，AI 可能混淆；</li><li>图片模糊、角度不清、细节不足时，识别错误概率会增加；</li><li>对专业设备、医学图像、法律文件、财务票据等高风险内容，不能完全依赖 AI 结果。</li></ul><h3 id="案例2" tabindex="-1">案例2 <a class="header-anchor" href="#案例2" aria-label="Permalink to “案例2”">​</a></h3><p>餐厅账单图片上显示：用户上传账单，并询问：“我应该付多少钱？我吃了拉面、芋泥奶茶和一半煎饺。”</p><p>AI 可以读取账单中的文字与金额，并结合用户描述完成计算。例如：</p><ul><li>识别账单项目；</li><li>找到对应价格；</li><li>计算一半煎饺的费用；</li><li>加上税费或相关费用；</li><li>输出用户应付金额。</li></ul><p><img src="'+n+'" alt="餐厅账单图片"></p><p>所以目前的 AI 能够处理“图片文字读取 + 用户条件 + 简单推理计算”的组合任务。</p><p>但这类结果仍然不适合直接用于高风险场景，最终金额最好人工核对。</p><h3 id="案例3" tabindex="-1">案例3 <a class="header-anchor" href="#案例3" aria-label="Permalink to “案例3”">​</a></h3><p>当我们的手写文字给 AI 进行识别转写时：</p><blockquote><p>此番言：对手写文字写别经常会有两种处理方式，比如目前版本的deepseek不是多模态模型，但是它对用户上传的图片是进行OCR进行识别；像KIMI这种多模态就是下面所讲的识别方法</p></blockquote><p><img src="'+h+'" alt="手写文字图片"></p><p>AI 可以识别部分手写文字，并生成大致转写结果。</p><p>手写识别的应用场景包括：</p><ul><li>转写旧日记；</li><li>整理家族信件；</li><li>数字化手写食谱；</li><li>从课堂笔记中提取内容；</li><li>从白板照片中整理会议记录。</li></ul><p>但手写内容的识别准确率受很多因素影响，例如字迹清晰度、拍摄角度、纸张污渍、光照、字体连笔程度等。</p><p>因此，手写转写结果需要人工校对，不能默认完全准确。</p><h3 id="案例4" tabindex="-1">案例4 <a class="header-anchor" href="#案例4" aria-label="Permalink to “案例4”">​</a></h3><p>一次 Prompt 中加入多张图片</p><p><img src="'+o+'" alt="手写文字图片"></p><p>如：</p><ul><li>白板照片；</li><li>便利贴照片；</li><li>会议现场图片；</li><li>手写草稿；</li><li>文档截图或文件。</li></ul><p>然后让 AI 完成类似任务：</p><blockquote><p>“总结今天头脑风暴会议中的想法。”</p></blockquote><p>AI 可以综合多张图片的信息，提取其中的主题、要点和行动项，生成会议总结。这种用法适合整理分散资料，把原本零碎的视觉信息整合为结构化文本。</p><p>不过，多图输入也可能出现遗漏或误读，因此视频建议对 AI 输出进行复查，尤其是会议纪要、决策记录、报价单、合同条款等重要内容。</p><h2 id="当你的prompt中使用图片-划重点" tabindex="-1">当你的Prompt中使用图片（划重点） <a class="header-anchor" href="#当你的prompt中使用图片-划重点" aria-label="Permalink to “当你的Prompt中使用图片（划重点）”">​</a></h2><p>1、图片要尽量清晰：</p><p>上传图片时，应保证主体完整、文字清楚、光线充足、角度稳定。如果图片模糊或被遮挡，AI 的判断会更容易出错。</p><p>2、问题要具体</p><p>不要只问“这是什么”，可以明确说明自己想知道什么，例如：</p><ul><li>“请提取图片中的文字。”</li><li>“请判断这张图中的设备名称。”</li><li>“请根据这张账单计算我应该支付的金额。”</li><li>“请把这些白板和便利贴内容整理成会议纪要。”</li></ul><p>问题越具体，AI 越容易给出符合需求的回答。</p><p>3、 告诉 AI 关注重点</p><p>如果图片中信息很多，可以指定重点区域或任务目标。例如：</p><ul><li>“只看右上角的表格。”</li><li>“重点识别红框中的文字。”</li><li>“忽略背景，只分析账单内容。”</li><li>“请把手写内容转成可编辑文本。”</li></ul><p>4、对重要结果进行复核</p><p>凡是涉及金额、身份、法律、医疗、安全、考试、合同等内容，都应人工核查。AI 可以作为辅助工具，但不应替代最终判断。</p><h2 id="可直接套用的-prompt-模板" tabindex="-1">可直接套用的 Prompt 模板 <a class="header-anchor" href="#可直接套用的-prompt-模板" aria-label="Permalink to “可直接套用的 Prompt 模板”">​</a></h2><p><strong>图片内容理解</strong></p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">请分析这张图片，说明图片中主要对象、文字信息和场景含义。请区分“图片中明确可见的信息”和“你推测的信息”。</span></span></code></pre></div><p><strong>图片文字提取</strong></p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">请提取图片中的所有可见文字，尽量保持原有顺序。如果有看不清的地方，请用【无法识别】标注，不要自行编造。</span></span></code></pre></div><p><strong>账单计算</strong></p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">请读取这张账单，并根据我的消费项目计算我应支付的金额。我的消费项目是：</span><span style="--shiki-light:#24292E;--shiki-light-font-style:italic;--shiki-dark:#E1E4E8;--shiki-dark-font-style:italic;">__</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">__。请列出每一项金额、计算过程和最终总额。无法确认的费用请单独说明。</span></span></code></pre></div><p><strong>手写笔记整理</strong></p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">请把这张手写笔记转写成可编辑文本，并在转写后整理成结构化笔记。无法确认的字词请保留疑问标记，不要强行补全。</span></span></code></pre></div><p><strong>多图会议总结</strong></p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">请综合这些图片中的白板、便利贴和笔记内容，整理成会议纪要。输出结构包括：会议主题、核心观点、待办事项、责任人、未确定问题。</span></span></code></pre></div><h2 id="此番言小结" tabindex="-1">此番言小结 <a class="header-anchor" href="#此番言小结" aria-label="Permalink to “此番言小结”">​</a></h2><p>图片可以直接加入 Prompt，成为 AI 理解任务的重要上下文。</p><p>AI 可以读取图片中的基础文字，理解图片场景，并根据用户问题完成说明、转写、计算和总结等任务。</p><p>但图像理解并不等于完全准确。AI 对粗粒度信息通常表现较好，对细节、模糊图像、相似物体和复杂手写内容仍可能出错。</p><p>在使用图片 Prompt 时，应尽量提供清晰图片、提出具体问题、明确关注区域，并对重要输出进行人工复核。</p><p><img src="'+d+'" alt="alt text"></p>',78)])])}const A=a(k,[["render",g]]);export{f as __pageData,A as default};
